CREATE TABLE `AbacoCurvaICPA` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `asentamientoCm` tinyint(3) unsigned NOT NULL COMMENT 'Asentamiento en cm (dominio válido: 4–20 cm inclusive)',
  `moduloFinura` decimal(4,2) NOT NULL COMMENT 'Módulo de finura total de la arena (anclas: 3.0, 3.5, 4.0, 4.5, 5.0, 5.5, 6.0, 6.5)',
  `formaAgregado` enum('CANTO_RODADO','TRITURADO','MIXTO') NOT NULL DEFAULT 'CANTO_RODADO' COMMENT 'Forma del agregado grueso. CANTO_RODADO = valores base. TRITURADO = base × 1.10. MIXTO = base × 1.05. Cada tabla es independiente y editable.',
  `aguaBaseLM3` decimal(5,0) NOT NULL COMMENT 'Agua base en L/m³ (entero). Solo depende de asentamiento + MF + forma. Sin correcciones de TMN.',
  `notas` text DEFAULT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT 1,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=409 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Ábaco 1 ICPA: agua base (L/m³) = f(asentamiento, MF, forma). Tres tablas completas: CANTO_RODADO (base), TRITURADO (×1.10), MIXTO (×1.05). Dominio: asentamiento 4–20 cm, MF 3.0–6.5. Corrección por TMN via CorrectoresICPA.';
