DROP TABLE IF EXISTS `Agregado`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `Agregado` (
  `idAgregado` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `nombre` varchar(40) NOT NULL,
  `origen` varchar(50) NOT NULL,
  `densidad` decimal(6,2) DEFAULT NULL,
  `pesoAparente` decimal(6,2) DEFAULT NULL,
  `absorcion` decimal(4,2) DEFAULT NULL,
  `moduloFinura` decimal(4,2) DEFAULT NULL,
  `idUnidadMedida` int(10) unsigned DEFAULT NULL,
  `idPlanta` int(10) unsigned DEFAULT NULL,
  `slotBetonmatic` varchar(10) DEFAULT NULL COMMENT 'Slot Betonmatic donde se carga este agregado en su planta (ej. "AR1"). Opción A — un material, un slot.',
  `ida` decimal(4,3) DEFAULT 1.000 COMMENT 'Índice de Demanda de Agua. 1.000 = estándar. >1 = más demanda, <1 = menos.',
  `idaModo` enum('auto','manual') NOT NULL DEFAULT 'auto' COMMENT 'auto = recalculado con ensayos, manual = valor fijado por el usuario.',
  `idaSugerido` decimal(4,3) DEFAULT NULL COMMENT 'IDA sugerido por el sistema basado en ensayos (pasa 200, absorción, etc.).',
  `idaNotas` text DEFAULT NULL COMMENT 'Justificación del IDA manual.',
  `activo` tinyint(1) NOT NULL DEFAULT 1,
  `aptitudes` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT 'Lista con valores HORMIGON, TBS_RODAMIENTO, TBS_NO_RODAMIENTO.' CHECK (json_valid(`aptitudes`)),
  `origenRoca` enum('ROCA_SANA','GRAVA','BASALTICO') DEFAULT NULL COMMENT 'Clasificación estructurada requerida por DNV TBS (basalto → Sonnenbrand; grava → relación partícula triturada).',
  `esCalizo` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'True si es caliza. DNV excluye calizos de capa de rodamiento.',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idAgregado`),
  KEY `idUnidadMedida` (`idUnidadMedida`),
  KEY `idPlanta` (`idPlanta`),
  CONSTRAINT `agregado_ibfk_1` FOREIGN KEY (`idUnidadMedida`) REFERENCES `UnidadMedida` (`idUnidadMedida`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `agregado_ibfk_2` FOREIGN KEY (`idPlanta`) REFERENCES `Planta` (`idPlanta`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Datos comunes de un agregado (ya sea fino o grueso).';
