  `nombreArchivo` varchar(255) NOT NULL,
  `url` varchar(500) NOT NULL,
  `mime` varchar(100) DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  PRIMARY KEY (`idAgregadoEnsayoArchivo`),
  KEY `idAgregadoEnsayo` (`idAgregadoEnsayo`),
  CONSTRAINT `agregadoensayoarchivo_ibfk_1` FOREIGN KEY (`idAgregadoEnsayo`) REFERENCES `AgregadoEnsayo` (`idAgregadoEnsayo`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Archivos adjuntos de ensayos de agregados.';
