--
-- Table structure for table `AgregadoEnsayoTipo`
--

DROP TABLE IF EXISTS `AgregadoEnsayoTipo`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `AgregadoEnsayoTipo` (
  `idAgregadoEnsayoTipo` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `codigo` varchar(80) NOT NULL,
  `nombre` varchar(200) NOT NULL,
  `normaRef` varchar(120) DEFAULT NULL,
  `aplicaA` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Array de strings, e.g. ["FINO","GRUESO"]. NULL = ambos.' CHECK (json_valid(`aplicaA`)),
  `unidad` varchar(30) DEFAULT NULL,
  `periodicidadMeses` int(10) unsigned DEFAULT NULL,
  `obligatorio` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Ensayo obligatorio según norma IRAM/CIRSOC',
  `warningDays` int(10) unsigned DEFAULT NULL COMMENT 'Días antes del vencimiento para mostrar alerta',
  `orden` int(10) unsigned NOT NULL DEFAULT 0 COMMENT 'Orden de presentación en la UI',
  `categoria` varchar(50) DEFAULT NULL COMMENT 'Agrupación: fisica, mecanica, limpieza, forma, durabilidad',
  `resultadoSchema` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`resultadoSchema`)),
  `esDerivado` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'true = se genera automáticamente a partir de otro ensayo',
  `derivadoDeCodigo` varchar(80) DEFAULT NULL COMMENT 'Codigo del AgregadoEnsayoTipo fuente',
  `derivadoClave` varchar(80) DEFAULT NULL COMMENT 'Clave en evaluacion.calculos del ensayo fuente',
  `isActive` tinyint(1) NOT NULL DEFAULT 1,
  `visibleEnDosificacion` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'true = aparece en dropdown de dosificación por defecto',
  `visibleEnCards` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'false = no mostrar como card ni contar como faltante (derivados)',
  `normaId` int(10) unsigned DEFAULT NULL COMMENT 'FK a Norma (catálogo de normas)',
  `material` varchar(30) NOT NULL DEFAULT 'AGREGADOS' COMMENT 'Material al que pertenece (AGREGADOS, HORMIGON, etc.)',
  `visibleEnUI` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Visible en la UI del catálogo de ensayos',
  `schemaKey` varchar(50) DEFAULT NULL COMMENT 'Método técnico / estructura de resultado (e.g. GRANULOMETRIA_1505, LOS_ANGELES)',
  `perfil` enum('CORE','AVANZADO') NOT NULL DEFAULT 'AVANZADO' COMMENT 'CORE = aparece por defecto; AVANZADO = solo si se activa el toggle',
  `visibleEnCaracterizacion` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'true = aparece en la ficha de caracterización del agregado',
  `caractFields` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Array de { key, label, labelCorto, unidad } que definen qué campos del resultado se muestran en caracterización' CHECK (json_valid(`caractFields`)),
  `aplicaATBS` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'True si el ensayo aplica al contexto TBS (además de hormigón).',
  `limitesDNV` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Límites DNV paramétricos (operador, porClaseTransito T1-T4, porOrigenRoca, criterios).' CHECK (json_valid(`limitesDNV`)),
  `aplicaAHormigon` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'True si el ensayo aplica al contexto Hormigón.',
  `obligatorioHormigon` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Obligatoriedad del ensayo en contexto Hormigón.',
  `obligatorioTBS` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Obligatoriedad del ensayo en contexto TBS.',
  `nivelCaracterizacionHormigon` enum('NINGUNA','BASICA','AVANZADA') NOT NULL DEFAULT 'NINGUNA' COMMENT 'Caract. Hormigón: NINGUNA=no aparece. BASICA=aparece y obligatorio fijo. AVANZADA=aparece, obligatorio configurable.',
  `nivelCaracterizacionTBS` enum('NINGUNA','BASICA','AVANZADA') NOT NULL DEFAULT 'NINGUNA' COMMENT 'Caract. TBS: NINGUNA=no aparece. BASICA=aparece y obligatorio fijo. AVANZADA=aparece, obligatorio configurable.',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idAgregadoEnsayoTipo`),
  UNIQUE KEY `codigo` (`codigo`),
  KEY `normaId` (`normaId`),
  CONSTRAINT `agregadoensayotipo_ibfk_1` FOREIGN KEY (`normaId`) REFERENCES `Norma` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Catálogo de tipos de ensayo para agregados (IRAM, etc.)';
/*!40101 SET character_set_client = @saved_cs_client */;

