INSERT INTO `AlertaCalidad` VALUES (1,'ENSAYO_INCONCLUYENTE','BAJO','PENDIENTE','Resultado no concluyente — Ensayo \"Cloruros solubles\" de \"Ripio lavado 6-19 mm\": Precisión del resultado (0.01%) insuficiente para verificar límite (0.003%). Solicitar ensayo con precisión <= 0.003%.','{\"codigoEnsayo\":\"IRAM1882_CLORUROS_SOLUBLES\",\"compliance\":{\"status\":\"inconclusive\",\"reason\":\"Precisión del resultado (0.01%) insuficiente para verificar límite (0.003%). Solicitar ensayo con precisión <= 0.003%.\",\"details\":[],\"rulesApplied\":[],\"measured\":null,\"limit\":{\"value\":0.003,\"comparator\":\"<=\",\"unidad\":\"%\"},\"norm\":\"IRAM 1531 / Tabla 1\",\"detection_limit\":null},\"complianceStatus\":\"inconclusive\"}',1,3,'Ripio lavado 6-19 mm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,NULL,'2026-06-23 22:11:44','2026-06-23 22:11:44'),(2,'ENSAYO_INCONCLUYENTE','BAJO','PENDIENTE','Resultado no concluyente — Ensayo \"Cloruros solubles\" de \"Ripio lavado 19-28 mm\": Precisión del resultado (0.01%) insuficiente para verificar límite (0.003%). Solicitar ensayo con precisión <= 0.003%.','{\"codigoEnsayo\":\"IRAM1882_CLORUROS_SOLUBLES\",\"compliance\":{\"status\":\"inconclusive\",\"reason\":\"Precisión del resultado (0.01%) insuficiente para verificar límite (0.003%). Solicitar ensayo con precisión <= 0.003%.\",\"details\":[],\"rulesApplied\":[],\"measured\":null,\"limit\":{\"value\":0.003,\"comparator\":\"<=\",\"unidad\":\"%\"},\"norm\":\"IRAM 1531 / Tabla 1\",\"detection_limit\":null},\"complianceStatus\":\"inconclusive\"}',1,4,'Ripio lavado 19-28 mm',NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,NULL,'2026-06-23 22:11:44','2026-06-23 22:11:44'),(3,'ENSAYO_NO_CUMPLE','ALTO','PENDIENTE','No cumple — Ensayo \"Suma de sustancias nocivas\" de \"Arena Común\": Suma de sustancias nocivas IRAM 1512: 5,34% supera el limite de 5% (con desgaste superficial). Componentes sumados: terrones 2,9%, pasa #200 2,2%, carbonosas 0,19%, sulfatos 0,01%, sales 0,03%, cloruros 0,01%.','{\"codigoEnsayo\":\"SUMA_NOCIVAS_AF\",\"compliance\":{\"status\":\"fail\",\"reasons\":[\"Suma de sustancias nocivas IRAM 1512: 5,34% supera el limite de 5% (con desgaste superficial). Componentes sumados: terrones 2,9%, pasa #200 2,2%, carbonosas 0,19%, sulfatos 0,01%, sales 0,03%, cloruros 0,01%.\"],\"expected\":null,\"actual\":null,\"details\":[],\"rulesApplied\":[],\"measured\":5.34,\"limit\":{\"value\":5,\"comparator\":\"<=\",\"unidad\":\"%\"},\"norm\":\"IRAM 1512 / §5.2.2 / Tabla 1\",\"severity\":\"no_bloqueante\"},\"complianceStatus\":\"fail\"}',1,2,'Arena Común',NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,NULL,'2026-06-23 22:12:18','2026-06-23 22:12:18'),(4,'','MEDIO','PENDIENTE','Tenés una dosificación pendiente de revisión: H-25 ARS.','{\"idDosificacionDisenada\":1,\"dosifNombre\":\"H-25 ARS\",\"enviadoPor\":\"Admin\",\"fechaEnvio\":\"2026-06-23T23:04:13.647Z\"}',1,NULL,NULL,1,'admin',NULL,NULL,NULL,NULL,NULL,0,NULL,'2026-06-23 23:04:13','2026-06-23 23:04:13'),(5,'','MEDIO','PENDIENTE','Tenés una dosificación pendiente de revisión: H-35 ARS bombeable.','{\"idDosificacionDisenada\":5,\"dosifNombre\":\"H-35 ARS bombeable\",\"enviadoPor\":\"Admin\",\"fechaEnvio\":\"2026-06-24T02:14:04.585Z\"}',1,NULL,NULL,5,'admin',NULL,NULL,NULL,NULL,NULL,0,NULL,'2026-06-24 02:14:04','2026-06-24 02:14:04');
