  `tareasRRHHHabilitado` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Si está habilitada la feature de declarar tarea al fichar (registro horario).',
  `tareasRRHHSolicitarPlanta` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Si al fichar se solicita seleccionar planta (recordando la del día anterior).',
  `tareasRRHHSolicitarDesgloseSalida` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Si al fichar la salida se pregunta por desglose horario de tareas realizadas.',
