  `combPermitirRetrocesoKm` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Si está activo, permite que los km ingresados sean menores al último registro (cambio de odómetro)',
  `combPermitirRetrocesoHoras` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Si está activo, permite que las horas ingresadas sean menores al último registro (cambio de horímetro)',
