  `tipo` enum('TMN','FORMA','AIRE') NOT NULL COMMENT 'Tipo de corrector. TMN y FORMA son legacy inactivos. AIRE = delta de agua (L/m³) por punto porcentual de aire incorporado sobre el aire base de referencia.',
  `descripcion` varchar(150) NOT NULL,
  `tmnMm` decimal(6,2) DEFAULT NULL COMMENT 'Legacy: TMN en mm al que aplica (solo tipo TMN, inactivo).',
  `formaAgregado` enum('TRITURADO','CANTO_RODADO','MIXTO') DEFAULT NULL COMMENT 'Legacy: forma del agregado (solo tipo FORMA, inactivo). La forma está integrada en AbacoCurvaICPA.',
  `deltaAguaLtsM3` decimal(6,1) NOT NULL COMMENT 'Delta de agua en L/m³. Positivo = más agua, negativo = menos agua.',
  `notas` text DEFAULT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT 1,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Correctores metodológicos para el método ICPA. TMN y FORMA son legacy (inactivos tras migraciones 20260313 y 20260315). Reservado para correcciones de aire incorporado (tipo AIRE) cuando se implementen.';
/*!40101 SET character_set_client = @saved_cs_client */;

