--
-- Table structure for table `CurvaCemento`
--

DROP TABLE IF EXISTS `CurvaCemento`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `CurvaCemento` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `cementoId` int(10) unsigned DEFAULT NULL COMMENT 'FK a Cemento. Null si es curva de familia/genérica.',
  `familiaCemento` varchar(30) DEFAULT NULL COMMENT 'Familia de cemento cuando no hay cemento específico asociado (CP30, CP40, CP50).',
  `idPlanta` int(10) unsigned DEFAULT NULL COMMENT 'NULL = curva global (típicamente del fabricante). Con valor = curva propia/experiencia exclusiva de esa planta.',
  `nombre` varchar(150) NOT NULL,
  `tipoCurva` enum('ABRAMS','TABLA_AC_RESISTENCIA') NOT NULL DEFAULT 'TABLA_AC_RESISTENCIA' COMMENT 'ABRAMS = parámetros A/B por edad; TABLA_AC_RESISTENCIA = puntos discretos.',
  `fuenteDocumento` varchar(200) DEFAULT NULL COMMENT 'Informe técnico o documento de referencia.',
  `fabricante` varchar(100) DEFAULT NULL,
  `plantaFabrica` varchar(100) DEFAULT NULL,
  `anioVigencia` int(10) unsigned DEFAULT NULL,
  `edadesDisponiblesJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Array de edades disponibles [1,2,3,7,28,56].' CHECK (json_valid(`edadesDisponiblesJson`)),
  `dMaxRefMm` decimal(6,2) DEFAULT NULL COMMENT 'Diámetro máximo de referencia para el que aplica la curva.',
  `version` varchar(20) DEFAULT NULL,
  `origenCurva` enum('ICPA','FABRICANTE','PROPIA') NOT NULL DEFAULT 'PROPIA',
  `observaciones` text DEFAULT NULL,
  `metadataJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`metadataJson`)),
  `activo` tinyint(1) NOT NULL DEFAULT 1,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `cementoId` (`cementoId`),
  KEY `idPlanta` (`idPlanta`),
  CONSTRAINT `curvacemento_ibfk_1` FOREIGN KEY (`cementoId`) REFERENCES `Cemento` (`idCemento`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `curvacemento_ibfk_2` FOREIGN KEY (`idPlanta`) REFERENCES `Planta` (`idPlanta`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Curvas de cemento tipo Abrams o tablas a/c vs resistencia, asociadas a un cemento específico o familia.';
/*!40101 SET character_set_client = @saved_cs_client */;

