--
-- Table structure for table `CurvaGranulometrica`
--

DROP TABLE IF EXISTS `CurvaGranulometrica`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `CurvaGranulometrica` (
  `idCurva` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `nombre` varchar(150) NOT NULL,
  `tipo` enum('TEORICA','BANDA','TABULADA') NOT NULL,
  `familia` varchar(30) DEFAULT NULL COMMENT 'Familia de curva teórica: FULLER, TALBOT, MAA, ANDREASEN, ROSIN_RAMMLER',
  `specMode` enum('RANGO','MAX_ONLY','MIN_ONLY','OBJETIVO') NOT NULL DEFAULT 'RANGO' COMMENT 'Modo de especificación: RANGO (min+max), MAX_ONLY, MIN_ONLY, OBJETIVO (targetPct)',
  `serieTamices` enum('IRAM','ASTM','CUSTOM') NOT NULL DEFAULT 'IRAM',
  `uso` enum('FINO','GRUESO','TOTAL') DEFAULT NULL COMMENT 'Tipo de agregado',
  `aplicaA` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'JSON array of uso values this curve applies to, e.g. ["FINO","GRUESO"]' CHECK (json_valid(`aplicaA`)),
  `tmnMm` double DEFAULT NULL COMMENT 'Tamaño máximo nominal en mm',
  `tmnMinMm` double DEFAULT NULL COMMENT 'Minimum TMN in mm for range-based matching',
  `tmnMaxMm` double DEFAULT NULL COMMENT 'Maximum TMN in mm for range-based matching',
  `curveLetter` varchar(5) DEFAULT NULL COMMENT 'Letra de curva IRAM 1627 (A, B, C)',
  `origenDatos` varchar(100) DEFAULT NULL COMMENT 'Origen de datos: IRAM, Pliego, Cliente, etc.',
  `estadoDatos` enum('PENDIENTE','COMPLETO') NOT NULL DEFAULT 'COMPLETO' COMMENT 'PENDIENTE = estructura sin datos, COMPLETO = con datos cargados',
  `normaRef` varchar(200) DEFAULT NULL COMMENT 'Norma de referencia (ej: IRAM 1627, ASTM C33)',
  `parametros` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Parámetros de fórmula: dmax, dmin, n, q, etc.' CHECK (json_valid(`parametros`)),
  `metadata` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Uso, notas, tags' CHECK (json_valid(`metadata`)),
  `isDefault` tinyint(1) NOT NULL DEFAULT 0,
  `isActive` tinyint(1) NOT NULL DEFAULT 1,
  `version` varchar(20) DEFAULT '1.0',
  `idCurvaSet` int(10) unsigned DEFAULT NULL COMMENT 'FK al set/paquete al que pertenece (optional)',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idCurva`),
  KEY `idCurvaSet` (`idCurvaSet`),
  CONSTRAINT `curvagranulometrica_ibfk_1` FOREIGN KEY (`idCurvaSet`) REFERENCES `CurvaSet` (`idCurvaSet`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Biblioteca de curvas granulométricas (teóricas, bandas, tabuladas).';
/*!40101 SET character_set_client = @saved_cs_client */;

