--
-- Table structure for table `CurvaPunto`
--

DROP TABLE IF EXISTS `CurvaPunto`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `CurvaPunto` (
  `idCurvaPunto` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `idCurva` int(10) unsigned NOT NULL,
  `idTamiz` int(10) unsigned NOT NULL COMMENT 'FK a Tamiz. Fuente de verdad estructural. La columna tamiz (STRING) se mantiene como label denormalizado hasta que se deprecie.',
  `tamiz` varchar(30) NOT NULL,
  `aberturaMm` double DEFAULT NULL,
  `pasaPct` double DEFAULT NULL COMMENT 'Para TABULADA: % pasa en ese tamiz',
  `limInfPct` double DEFAULT NULL COMMENT 'Para BANDA: límite inferior % pasa',
  `limSupPct` double DEFAULT NULL COMMENT 'Para BANDA: límite superior % pasa',
  `targetPct` double DEFAULT NULL COMMENT 'Para specMode OBJETIVO: % pasa objetivo',
  `isNA` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'true = punto N/A, se omite de validación y gráfico',
  `orden` int(11) NOT NULL DEFAULT 0,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idCurvaPunto`),
  KEY `idCurva` (`idCurva`),
  KEY `idTamiz` (`idTamiz`),
  CONSTRAINT `curvapunto_ibfk_1` FOREIGN KEY (`idCurva`) REFERENCES `CurvaGranulometrica` (`idCurva`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `curvapunto_ibfk_2` FOREIGN KEY (`idTamiz`) REFERENCES `Tamiz` (`idTamiz`) ON DELETE NO ACTION ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=361 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Puntos individuales para curvas TABULADA y BANDA.';
/*!40101 SET character_set_client = @saved_cs_client */;

