  `idCurvaSet` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `nombre` varchar(200) NOT NULL COMMENT 'Nombre descriptivo del set (ej: "IRAM 1627 Grueso TMN 19")',
  `serieTamices` enum('IRAM','ASTM','CUSTOM') NOT NULL DEFAULT 'IRAM',
  `materialUso` enum('FINO','GRUESO','TOTAL') DEFAULT NULL COMMENT 'Tipo de agregado',
  `tmnMm` double DEFAULT NULL COMMENT 'Tamaño máximo nominal en mm',
  `normaRef` varchar(200) DEFAULT NULL COMMENT 'Norma de referencia (ej: IRAM 1627)',
  `descripcion` text DEFAULT NULL,
  `estado` enum('COMPLETO','PENDIENTE') NOT NULL DEFAULT 'PENDIENTE' COMMENT 'PENDIENTE = estructura creada pero sin datos cargados',
  `isDefault` tinyint(1) NOT NULL DEFAULT 0,
  `isActive` tinyint(1) NOT NULL DEFAULT 1,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idCurvaSet`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Paquetes/sets de curvas granulométricas (ej: bandas IRAM por TMN).';
