  `requiereProteccionSuperficial` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Indica si la clase requiere protección superficial adicional.',
  `orden` int(10) unsigned NOT NULL DEFAULT 99 COMMENT 'Orden de presentación en catálogos y dropdowns.',
