  `fechaEnsayo` date NOT NULL,
  `horaEnsayo` time NOT NULL,
  `edadEnsayo` smallint(5) unsigned NOT NULL COMMENT 'Días desde la confección de la probeta (Muestra.fecha) hasta fechaEnsayo',
