  `idLaboratorio` int(10) unsigned DEFAULT NULL COMMENT 'Snapshot del laboratorio que ejecutó el ensayo. Auto-populado por hook desde la prensa si no se manda.',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idEnsayoResistencia`),
  UNIQUE KEY `uq_ensayoresistencia_idprobeta` (`idProbeta`),
  KEY `idOperarioEnsayo` (`idOperarioEnsayo`),
  KEY `idPrensa` (`idPrensa`),
  KEY `idAprobadoPor` (`idAprobadoPor`),
  KEY `idCalibracionAplicada` (`idCalibracionAplicada`),
  KEY `idLaboratorio` (`idLaboratorio`),
  CONSTRAINT `ensayoresistencia_ibfk_1` FOREIGN KEY (`idProbeta`) REFERENCES `Probeta` (`idProbeta`) ON DELETE NO ACTION ON UPDATE CASCADE,
  CONSTRAINT `ensayoresistencia_ibfk_2` FOREIGN KEY (`idOperarioEnsayo`) REFERENCES `Empleado` (`idEmpleado`) ON DELETE NO ACTION ON UPDATE CASCADE,
  CONSTRAINT `ensayoresistencia_ibfk_3` FOREIGN KEY (`idPrensa`) REFERENCES `Prensa` (`idPrensa`) ON DELETE NO ACTION ON UPDATE CASCADE,
  CONSTRAINT `ensayoresistencia_ibfk_4` FOREIGN KEY (`idAprobadoPor`) REFERENCES `Empleado` (`idEmpleado`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `ensayoresistencia_ibfk_5` FOREIGN KEY (`idCalibracionAplicada`) REFERENCES `CalibracionEquipo` (`idCalibracion`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `ensayoresistencia_ibfk_6` FOREIGN KEY (`idLaboratorio`) REFERENCES `Laboratorio` (`idLaboratorio`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Resultados de resistencia, con la edad de ensayo almacenada y calculada en la capa de aplicación. Se audita.';
