  `certificadoVigente` tinyint(1) DEFAULT 0 COMMENT 'Indica si la última calibración está vigente (denormalizado).',
  `activo` tinyint(1) NOT NULL DEFAULT 1,
  `deleted_at` datetime DEFAULT NULL COMMENT 'Borrado lógico.',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idEquipo`),
