  `aguaAgregadaLts` decimal(8,2) DEFAULT NULL COMMENT 'Agua agregada en este punto (L). Usar para ajustes de slump.',
  `aditivoAgregadoNombre` varchar(120) DEFAULT NULL COMMENT 'Nombre/marca del aditivo agregado en este punto.',
  `aditivoAgregadoCantidad` decimal(10,3) DEFAULT NULL COMMENT 'Cantidad total agregada del aditivo (en la unidad indicada).',
