  `volumenRemanenteM3` decimal(6,3) DEFAULT NULL COMMENT 'Volumen de hormigón remanente en el camión al momento de la medición (m³). Si no se indica, se asume el de la medición anterior (o el volumen total del pastón).',
  `aguaRetenidaLts` decimal(8,2) DEFAULT NULL COMMENT 'Agua dosificada pero retenida (no incorporada) para usar después.',
  `aditivoRetenidoNombre` varchar(120) DEFAULT NULL,
  `aditivoRetenidoCantidad` decimal(10,3) DEFAULT NULL,
  `aditivoRetenidoUnidad` varchar(10) DEFAULT NULL,
