--
-- Table structure for table `MezclaAgregados`
--

DROP TABLE IF EXISTS `MezclaAgregados`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `MezclaAgregados` (
  `idMezcla` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `nombre` varchar(200) NOT NULL,
  `descripcion` text DEFAULT NULL,
  `idPlanta` int(10) unsigned NOT NULL,
  `tipoMezcla` enum('FINO','GRUESO','TOTAL') NOT NULL,
  `objetivoModo` enum('BANDA','CURVA','COMBINADO') DEFAULT NULL,
  `idBanda` int(10) unsigned DEFAULT NULL,
  `idCurvaTeorica` int(10) unsigned DEFAULT NULL,
  `bandaCompuestaJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`bandaCompuestaJson`)),
  `prioridad1` enum('BANDA','CURVA') DEFAULT NULL,
  `prioridad2` enum('BANDA','CURVA') DEFAULT NULL,
  `tmnCalculadoMm` double DEFAULT NULL,
  `moduloFinura` double DEFAULT NULL,
  `curvaMezclaJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`curvaMezclaJson`)),
  `metadataResultadoJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`metadataResultadoJson`)),
  `isActive` tinyint(1) NOT NULL DEFAULT 1,
  `estado` enum('BORRADOR','A_PRUEBA','PENDIENTE_REVISION','APROBADO','SUSPENDIDO','ARCHIVADO') NOT NULL DEFAULT 'BORRADOR',
  `version` int(10) unsigned NOT NULL DEFAULT 1,
  `versionPadreId` int(10) unsigned DEFAULT NULL,
  `mezclaBaseId` int(10) unsigned DEFAULT NULL COMMENT 'Root ID of version chain (= self in v1)',
  `codigo` varchar(50) DEFAULT NULL,
  `codigoBase` varchar(50) DEFAULT NULL,
  `hashIntegridad` varchar(64) DEFAULT NULL,
  `hashDatosJson` longtext DEFAULT NULL,
  `aprobadoPor` varchar(255) DEFAULT NULL,
  `fechaAprobacion` datetime DEFAULT NULL,
  `observacionesAprobacion` text DEFAULT NULL,
  `enviadoRevisionPor` varchar(255) DEFAULT NULL,
  `fechaEnvioRevision` datetime DEFAULT NULL,
  `motivoSuspension` text DEFAULT NULL,
  `suspendidoPor` varchar(255) DEFAULT NULL,
  `fechaSuspension` datetime DEFAULT NULL,
  `archivadoPor` varchar(255) DEFAULT NULL,
  `fechaArchivo` datetime DEFAULT NULL,
  `reemplazadaPorId` int(10) unsigned DEFAULT NULL,
  `tipoOptimizacion` varchar(30) DEFAULT NULL,
  `proporcionesOptimasJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`proporcionesOptimasJson`)),
  `rangosFactiblesJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`rangosFactiblesJson`)),
  `metricasOptimoJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`metricasOptimoJson`)),
  `metricasAdoptadoJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`metricasAdoptadoJson`)),
  `calidadAjuste` varchar(15) DEFAULT NULL,
  `motivoAjuste` text DEFAULT NULL,
  `deletedAt` datetime DEFAULT NULL,
  `deletedBy` varchar(255) DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idMezcla`),
  KEY `idPlanta` (`idPlanta`),
  KEY `idBanda` (`idBanda`),
  KEY `idCurvaTeorica` (`idCurvaTeorica`),
  CONSTRAINT `mezclaagregados_ibfk_1` FOREIGN KEY (`idPlanta`) REFERENCES `Planta` (`idPlanta`) ON DELETE NO ACTION ON UPDATE CASCADE,
  CONSTRAINT `mezclaagregados_ibfk_2` FOREIGN KEY (`idBanda`) REFERENCES `CurvaGranulometrica` (`idCurva`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `mezclaagregados_ibfk_3` FOREIGN KEY (`idCurvaTeorica`) REFERENCES `CurvaGranulometrica` (`idCurva`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

