2009,'Índice de elongación (partículas alargadas).',NULL,3,'2026-06-23 00:03:00','2026-06-23 00:03:00'),(21,'IRAM 1700','Agregados. Reactividad alcalina potencial. Método químico','IRAM',NULL,1997,'Determinación de reactividad alcalina potencial por método químico.',NULL,3,'2026-06-23 00:03:00','2026-06-23 00:03:00'),(22,'IRAM 1709','Hormigón de cemento. Método y requisitos para el uso de placas de elastómero no adheridas, empleadas para la determinación de la resistencia a la compresión de probetas y testigos cilíndricos de hormigón endurecido','IRAM','2016',2016,NULL,NULL,5,'2026-06-23 00:03:00','2026-06-23 00:03:00'),(23,'IRAM 1874-1','Agregados. Reactividad alcalina potencial. Método de prisma de hormigón (Parte 1)','IRAM',NULL,2004,'Ensayo de reactividad alcalina mediante prisma de hormigón.',NULL,3,'2026-06-23 00:03:00','2026-06-23 00:03:00'),(24,'IRAM 1874-2','Agregados. Reactividad alcalina potencial. Método de la barra de mortero (Parte 2)','IRAM',NULL,2004,'Ensayo de reactividad alcalina mediante barra de mortero.',NULL,3,'2026-06-23 00:03:00','2026-06-23 00:03:00'),(25,'IRAM 1874-3','Agregados. Reactividad alcalina potencial. Método acelerado de la barra de mortero (Parte 3)','IRAM',NULL,2004,'Ensayo acelerado de reactividad alcalina mediante barra de mortero.',NULL,3,'2026-06-23 00:03:00','2026-06-23 00:03:00'),(26,'IRAM 1882','Agregados finos. Valor equivalente de arena','IRAM',NULL,2004,'Ensayo de equivalente de arena para evaluar limpieza.',NULL,3,'2026-06-23 00:03:00','2026-06-23 00:03:00'),(27,'IRAM 1887','Agregados finos. Ensayo de azul de metileno','IRAM',NULL,2014,'Evaluación de presencia de arcillas mediante azul de metileno.',NULL,3,'2026-06-23 00:03:00','2026-06-23 00:03:00');
