DROP TABLE IF EXISTS `OverrideRequest`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `OverrideRequest` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `idDosificacionDisenada` int(10) unsigned NOT NULL COMMENT 'Diseño para el que se solicita la liberación.',
  `idMezcla` int(10) unsigned NOT NULL COMMENT 'Mezcla con condición requires_technical_evidence que gatilla el override.',
  `idMaterial` int(10) unsigned DEFAULT NULL COMMENT 'Material puntual de la mezcla (nullable = aplica a todos los materiales de la mezcla).',
  `ambito` enum('OBRA','AUTOCONTROL_PLANTA') NOT NULL COMMENT 'OBRA = Director Técnico matriculado; AUTOCONTROL_PLANTA = Responsable de Calidad.',
  `estado` enum('PENDIENTE','APROBADO','RECHAZADO') NOT NULL DEFAULT 'PENDIENTE',
  `motivo` text NOT NULL COMMENT 'Justificación técnica del pedido (quién lo redacta al solicitarlo).',
  `evidenciaAlternativaDescripcion` text DEFAULT NULL COMMENT 'Evidencia parcial o informal que no llega a registrarse como TechnicalEvidence (ej: obra similar sin informe formal).',
  `solicitadoPor` varchar(120) NOT NULL,
  `rolSolicitante` varchar(40) DEFAULT NULL,
  `fechaSolicitud` datetime NOT NULL,
  `resueltoPor` varchar(120) DEFAULT NULL,
  `rolResolutor` varchar(40) DEFAULT NULL,
  `matriculaResolutor` varchar(40) DEFAULT NULL COMMENT 'Matrícula del Director Técnico cuando ámbito = OBRA (para estampar en PDF K.4).',
  `fechaResolucion` datetime DEFAULT NULL,
  `observacionesResolucion` text DEFAULT NULL,
  `activo` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Soft-delete: false = revocado / invalidado por cambio en el diseño.',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `override_request_id_dosificacion_disenada` (`idDosificacionDisenada`),
  KEY `override_request_id_mezcla` (`idMezcla`),
  KEY `override_request_estado` (`estado`),
  KEY `override_request_activo` (`activo`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Log auditable de overrides CIRSOC §3.2.3.2 f) (Bloque K.3).';
