  `reusosExtendidos` int(11) NOT NULL DEFAULT 0 COMMENT 'Cantidad de extensiones otorgadas más allá del máximo normativo (máx 50% de reusosMaxNorma).',
  `estado` enum('EN_STOCK','EN_USO','AGOTADO','DESCARTADO') NOT NULL DEFAULT 'EN_STOCK' COMMENT 'EN_STOCK = disponible en planta. EN_USO = activo en prensa. AGOTADO = consumido. DESCARTADO = retirado.',
  `fechaActivacion` datetime DEFAULT NULL COMMENT 'Fecha de asignación a prensa (EN_STOCK → EN_USO).',
  `fechaBaja` datetime DEFAULT NULL COMMENT 'Fecha de retiro (AGOTADO o DESCARTADO).',
  `motivoBaja` enum('LIMITE_ALCANZADO','DETERIORO','REEMPLAZO_PREVENTIVO','OTRO') DEFAULT NULL,
  `observacionesBaja` text DEFAULT NULL,
  `marca` varchar(100) DEFAULT NULL,
  `identificacion` varchar(50) DEFAULT NULL COMMENT 'Identificación autogenerada PG-NNNN (150 mm) o PC-NNNN (100 mm).',
  `observaciones` text DEFAULT NULL,
  `creadoPor` varchar(255) DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idPlacaElastomero`),
  KEY `idx_planta_estado` (`idPlanta`,`estado`),
