  `cantidadTolvas` int(10) unsigned DEFAULT 4 COMMENT 'Cantidad de tolvas de agregados disponibles en la planta',
  `betonmaticActivo` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Si la integración con Betonmatic está habilitada',
  `betonmaticCfClientId` varchar(255) DEFAULT NULL COMMENT 'CF-Access-Client-Id para Cloudflare Zero Trust',
  `betonmaticCfClientSecret` varchar(255) DEFAULT NULL COMMENT 'CF-Access-Client-Secret para Cloudflare Zero Trust',
