  `m3PorBatch` double DEFAULT NULL COMMENT 'Capacidad del mezclador en m³ por batch. Se envía como `M3xBatch` al publicar fórmulas a Betonmatic; sin este valor la planta no carga la fórmula.',
  `capacidadBalanzaCementoKg` decimal(10,2) DEFAULT NULL COMMENT 'Capacidad máx. (kg) de la tolva balanza de cemento/adiciones — IRAM 1666 Tabla 7 (>30%/≤30%).',
  `capacidadBalanzaAridosKg` decimal(10,2) DEFAULT NULL COMMENT 'Capacidad máx. (kg) de la báscula de áridos (única para los 4 áridos) — IRAM 1666 Tabla 7.',
  `origenDosificaciones` enum('DISENADOR','ESTATICA') NOT NULL DEFAULT 'ESTATICA' COMMENT 'De dónde salen las dosificaciones para los despachos: DISENADOR (motor Calidad) o ESTATICA (catálogo legacy). DISENADOR requiere módulo Calidad activo en el tenant.',
  `googleMapsPlaceUrl` varchar(500) DEFAULT NULL COMMENT 'URL del perfil de Google Maps del negocio',
  `modoProduccion` enum('1','2') NOT NULL DEFAULT '2' COMMENT 'IRAM 1666 / CIRSOC §6.2 — Modo 1: SGC certificado / Modo 2: sin SGC. Default 2 (más conservador).',
  `sgcOrganismo` varchar(120) DEFAULT NULL COMMENT 'PR8.18 — Modo 1: organismo certificador del SGC (ej: IRAM, IAS).',
  `sgcVigenciaHasta` date DEFAULT NULL COMMENT 'PR8.18 — Modo 1: fecha de vigencia del certificado SGC.',
  `sgcAlcance` varchar(255) DEFAULT NULL COMMENT 'PR8.18 — Modo 1: alcance del SGC (ej: "Producción de hormigón elaborado").',
  `rdcModoDensidad` enum('REDUCCION_PCT','PUV_OBJETIVO') NOT NULL DEFAULT 'REDUCCION_PCT' COMMENT 'RDC: cómo se fija la densidad objetivo. REDUCCION_PCT = % sobre el mortero base; PUV_OBJETIVO = valor fijo.',
  `rdcPuvObjetivoKgM3` int(10) unsigned DEFAULT NULL COMMENT 'RDC modo PUV_OBJETIVO: densidad fresca objetivo (kg/m³). Null → default del motor (1650, Segerer 2017).',
  `rdcReduccionPct` decimal(4,1) DEFAULT NULL COMMENT 'RDC modo REDUCCION_PCT: % de reducción respecto del mortero base sin aire. Null → default del motor (22%).',
  `rdcPuvToleranciaKgM3` int(10) unsigned DEFAULT NULL COMMENT 'RDC: tolerancia de control del PUV (±kg/m³) para el warning de densidad. Null → default del motor (80, Segerer 2017).',
  `rdcFactorAguaConsistencia` decimal(4,3) DEFAULT NULL COMMENT 'RDC Fase 3: factor multiplicativo único de calibración del agua por consistencia (por planta). Null → 1,0 (motor).',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`idPlanta`),
  KEY `idEntidad` (`idEntidad`),
  CONSTRAINT `planta_ibfk_1` FOREIGN KEY (`idEntidad`) REFERENCES `Entidad` (`idEntidad`) ON DELETE NO ACTION ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Plantas de hormigón, pueden haber varias en distintas ubicaciones.';
