CREATE TABLE `TechnicalEvidence` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `tipo` enum('LAB_STUDY','PRIOR_PROJECT') NOT NULL COMMENT 'LAB_STUDY = estudio de laboratorio; PRIOR_PROJECT = antecedente de obra similar.',
  `referencia` varchar(160) NOT NULL COMMENT 'Ej: "INF-LAB-2026-0042" o "Proyecto Edificio Quebradas 2024".',
  `fecha` date NOT NULL COMMENT 'Fecha del informe / del antecedente de obra.',
  `descripcion` text NOT NULL COMMENT 'Descripción de la evidencia, alcance, condiciones bajo las que se obtuvo.',
  `laboratorio` varchar(120) DEFAULT NULL COMMENT 'Nombre del laboratorio (para LAB_STUDY) o de la obra/cliente (para PRIOR_PROJECT).',
  `urlAdjunto` varchar(500) DEFAULT NULL COMMENT 'MVP textual: link al documento si está hosteado externamente. Upload de archivos queda para sprint futuro.',
  `materialesAsociados` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT 'Array de idAgregado / idMaterial a los que respalda esta evidencia.' CHECK (json_valid(`materialesAsociados`)),
  `dosificacionesAsociadas` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT 'Array de idDosificacionDisenada a las que respalda específicamente.' CHECK (json_valid(`dosificacionesAsociadas`)),
  `claseResistenciaAplicable` varchar(10) DEFAULT NULL COMMENT 'Clase de resistencia hasta la cual aplica esta evidencia (ej: H20, H25). null = sin restricción declarada.',
  `responsableCarga` varchar(120) NOT NULL COMMENT 'Nombre del usuario que cargó la evidencia.',
  `rolCarga` varchar(40) DEFAULT NULL COMMENT 'Rol del usuario al cargar (RESPONSABLE_CALIDAD, DIRECTOR_TECNICO, ...).',
  `activo` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Soft-delete: false = retirada del repositorio (no eliminada físicamente).',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `technical_evidence_tipo` (`tipo`),
  KEY `technical_evidence_activo` (`activo`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Repositorio de evidencias técnicas para excepciones normativas (P3.8 / CIRSOC §3.2.3.2 f).';
