  `restriccionesGranulometricas` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '{"pasa_0_075_min":null,"pasa_0_15_min":null,"pasa_0_30_min":null,"tmn_max":null,"tmn_min":null,"mf_max":null,"mf_min":null,"relacion_finos_min":null,"relacion_finos_max":null,"vol_gruesos_max":null,"polvo_min_kg":null}' CHECK (json_valid(`restriccionesGranulometricas`)),
