INSERT INTO `TipologiaHormigon` VALUES (1,'convencional','Convencional / Estructural','Hormigón vibrado estándar para estructuras de edificación y obras civiles generales.',1,'FULLER_TALBOT',0.500,'{}','{\"asentamiento_recomendado_min\":8,\"asentamiento_recomendado_max\":15}',1,0,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(2,'bombeable','Bombeable','Hormigón diseñado para ser trasladado por tubería a presión. Mayor contenido de finos.',1,'FULLER_TALBOT',0.450,'{\"pasa_0_15_min\":10,\"pasa_0_30_min\":15,\"tmn_max\":25,\"mf_max\":4.5,\"relacion_finos_min\":40}','{\"asentamiento_min\":12,\"asentamiento_max\":22,\"asentamiento_recomendado_min\":15,\"asentamiento_recomendado_max\":20,\"vol_pasta_min\":300,\"aditivos_recomendados\":[\"superplastificante\"]}',1,1,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(3,'autocompactante','Autocompactante (HAC)','Hormigón que fluye y se compacta por su propio peso sin vibración. Requiere superplastificante.',1,'ANDREASEN_MOD',0.280,'{\"tmn_max\":19,\"vol_gruesos_max\":350,\"polvo_min_kg\":450,\"relacion_finos_min\":50,\"mf_max\":4.0}','{\"tipo_trabajabilidad\":\"escurrimiento\",\"asentamiento_min\":55,\"asentamiento_max\":80,\"asentamiento_recomendado_min\":60,\"asentamiento_recomendado_max\":75,\"vol_pasta_min\":340,\"aditivos_requeridos\":[\"superplastificante\"],\"aditivos_recomendados\":[\"viscosante\"]}',1,2,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(4,'masivo','Masivo (bajo calor)','Hormigón para elementos de gran volumen. TMN grande, pocos finos, bajo calor de hidratación.',1,'FULLER_TALBOT',0.550,'{\"tmn_min\":37.5,\"mf_min\":5.0,\"relacion_finos_max\":40}','{\"asentamiento_recomendado_min\":4,\"asentamiento_recomendado_max\":10,\"cemento_max_kg\":300,\"aditivos_recomendados\":[\"retardante\"]}',1,3,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(5,'pavimento_rigido','Pavimento rígido','Hormigón para pavimentos de carreteras, pisos industriales. Baja trabajabilidad, alta resistencia a flexión.',1,'FULLER_TALBOT',0.500,'{}','{\"asentamiento_recomendado_min\":2,\"asentamiento_recomendado_max\":6}',1,4,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(6,'proyectado','Hormigón proyectado (shotcrete)','Hormigón aplicado por proyección neumática. TMN pequeño, alta cohesión.',1,'FULLER_TALBOT',0.400,'{\"tmn_max\":12.5,\"pasa_0_30_min\":20,\"mf_max\":4.0}','{\"asentamiento_recomendado_min\":4,\"asentamiento_recomendado_max\":8,\"aditivos_requeridos\":[\"acelerante\"]}',1,5,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(7,'alta_resistencia','Alta resistencia (> 50 MPa)','Hormigones con f\'ck > 50 MPa. Baja a/c, alto contenido de cementíceos.',1,'FULLER_TALBOT',0.450,'{\"tmn_max\":19}','{\"asentamiento_recomendado_min\":12,\"asentamiento_recomendado_max\":20,\"aditivos_requeridos\":[\"superplastificante\"]}',1,6,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(8,'arquitectonico','Arquitectónico / Visto','Hormigón donde la superficie es la terminación final. Requiere uniformidad y buen acabado.',1,'FULLER_TALBOT',0.420,'{\"tmn_max\":19,\"relacion_finos_min\":45}','{\"asentamiento_recomendado_min\":12,\"asentamiento_recomendado_max\":18}',1,7,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(9,'rcc','Compactado con rodillo (RCC)','Hormigón seco compactado con rodillo. TMN grande, sin asentamiento.',1,'FULLER_TALBOT',0.550,'{\"tmn_min\":37.5}','{\"asentamiento_recomendado_min\":0,\"asentamiento_recomendado_max\":2}',1,8,'0000-00-00 00:00:00','0000-00-00 00:00:00'),(10,'personalizado','Personalizado','Tipología con parámetros completamente configurables por el usuario.',1,'FULLER_TALBOT',0.500,'{}','{}',1,99,'0000-00-00 00:00:00','0000-00-00 00:00:00');
/*!40000 ALTER TABLE `TipologiaHormigon` ENABLE KEYS */;
